-- FSI_DEMO_DB.CAPITAL_MARKETS.NEWS_ARTICLES

CREATE OR REPLACE TABLE FSI_DEMO_DB.CAPITAL_MARKETS.NEWS_ARTICLES (

    ARTICLE_ID VARCHAR(20) NOT NULL,
    PUBLISH_DATE TIMESTAMP_NTZ(9),
    SOURCE VARCHAR(100),
    AUTHOR VARCHAR(100),
    HEADLINE VARCHAR(500),
    CONTENT VARCHAR(16777216),
    SUMMARY VARCHAR(1000),
    URL VARCHAR(500),
    TICKERS_MENTIONED VARCHAR(500),
    SECTORS_MENTIONED VARCHAR(200),
    ARTICLE_TYPE VARCHAR(50),
    SENTIMENT_SCORE NUMBER(5,4),
    SENTIMENT_LABEL VARCHAR(20),
    RELEVANCE_SCORE NUMBER(5,4),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (ARTICLE_ID)

);



