INSERT INTO FSI_DEMO_DB.CAPITAL_MARKETS.NEWS_ARTICLES (ARTICLE_ID, PUBLISH_DATE, SOURCE, AUTHOR, HEADLINE, CONTENT, SUMMARY, URL, TICKERS_MENTIONED, SECTORS_MENTIONED, ARTICLE_TYPE, SENTIMENT_SCORE, SENTIMENT_LABEL, RELEVANCE_SCORE, CREATED_AT) VALUES
('NEWS0001000', '2025-12-10 03:47:19.757', 'Reuters', 'Analysis Team', 'Tech Stocks Rally on Strong Earnings Reports', 'Technology stocks led the market higher today following a series of better-than-expected earnings reports from major companies. The NASDAQ composite gained 2.3% as investors responded positively to strong revenue growth and improved guidance from several bellwether tech names. Analysts noted that cloud computing and artificial intelligence continue to be key growth drivers across the sector. Trading volume was above average as institutional investors increased their technology allocations.', 'Tech stocks rally on earnings beats; NASDAQ up 2.3%', 'https://financial-news.example.com/article/1000', 'AAPL,MSFT,GOOGL,NVDA', 'Technology', 'FEATURE', '0.7500', 'POSITIVE', '0.6000', '2026-02-17 14:27:19.757'),
('NEWS0001001', '2025-12-10 02:07:19.757', 'Bloomberg', 'Editorial Board', 'Federal Reserve Signals Potential Rate Cut', 'The Federal Reserve indicated today that it may consider cutting interest rates in the coming months if inflation continues to moderate. In prepared remarks, Fed Chair emphasized that the central bank remains data-dependent but acknowledged recent progress on price stability. Treasury yields fell sharply on the news, with the 10-year note dropping 15 basis points. Equity markets rallied broadly as investors priced in a more accommodative monetary policy stance.', 'Fed signals potential rate cuts; Treasury yields fall sharply', 'https://financial-news.example.com/article/1001', 'JPM,BAC,GS,C', 'Financials', 'MARKET_WRAP', '0.7100', 'POSITIVE', '0.6100', '2026-02-17 14:27:19.757'),
('NEWS0001002', '2025-12-10 00:27:19.757', 'Wall Street Journal', 'Editorial Board', 'Oil Prices Surge Amid Middle East Tensions', 'Crude oil prices jumped more than 4% today amid escalating geopolitical tensions in the Middle East. Brent crude futures rose to $95 per barrel, the highest level in six months, as traders assessed potential supply disruptions. Energy stocks outperformed the broader market, with major oil producers seeing gains of 5-8%. Analysts cautioned that sustained higher oil prices could weigh on consumer spending and corporate margins in the coming quarters.', 'Oil prices surge 4% on Middle East tensions; energy stocks outperform', 'https://financial-news.example.com/article/1002', 'XOM,CVX,COP', 'Energy', 'BREAKING', '0.3200', 'NEUTRAL', '0.6200', '2026-02-17 14:27:19.757'),
('NEWS0001003', '2025-12-09 22:47:19.757', 'CNBC', 'Editorial Board', 'Major Merger Announced in Healthcare Sector', 'A major merger was announced today in the healthcare sector, with two pharmaceutical giants agreeing to combine in a $50 billion deal. The transaction is expected to close in the first quarter pending regulatory approval. Management cited synergies in research and development as a key driver of the combination. The deal would create one of the worlds largest drug makers with a combined pipeline of over 100 candidates in various stages of development.', 'Healthcare merger: $50B deal creates pharma giant', 'https://financial-news.example.com/article/1003', 'JNJ,PFE,MRK,ABBV', 'Healthcare', 'ANALYSIS', '0.2300', 'NEUTRAL', '0.6300', '2026-02-17 14:27:19.757'),
('NEWS0001004', '2025-12-09 21:07:19.757', 'Financial Times', 'Editorial Board', 'Retail Sales Data Exceeds Expectations', 'Retail sales data released today showed consumer spending increased by 0.8% in the latest month, exceeding economist expectations of 0.5% growth. The stronger-than-expected reading suggests resilient consumer demand despite higher interest rates. Department store and online retailers reported particularly strong results. The data provides further evidence that the economy continues to grow at a healthy pace, reducing concerns about an imminent recession.', 'Retail sales up 0.8% vs 0.5% expected; consumer resilient', 'https://financial-news.example.com/article/1004', 'AMZN,WMT,TGT,COST', 'Consumer', 'EARNINGS', '0.2400', 'NEUTRAL', '0.6400', '2026-02-17 14:27:19.757'),
('NEWS0001005', '2025-12-09 19:27:19.757', 'MarketWatch', 'John Smith', 'Cryptocurrency Markets Experience Volatility', 'Cryptocurrency markets experienced significant volatility today as Bitcoin briefly dropped below $40,000 before recovering to trade near $42,000. The selloff was attributed to regulatory concerns and profit-taking following the recent rally. Ethereum and other major altcoins followed a similar pattern. Despite the turbulence, crypto proponents maintain a bullish long-term outlook citing institutional adoption and upcoming technical upgrades.', 'Crypto volatility: Bitcoin drops below $40K before recovering', 'https://financial-news.example.com/article/1005', 'BTC,ETH', 'Crypto', 'ECONOMIC_DATA', '-0.1500', 'NEUTRAL', '0.6500', '2026-02-17 14:27:19.757'),
('NEWS0001006', '2025-12-09 17:47:19.757', 'Barrons', 'Sarah Johnson', 'Supply Chain Concerns Weigh on Industrial Stocks', 'Industrial stocks came under pressure today as ongoing supply chain disruptions continued to impact manufacturing operations. Several major companies lowered their full-year guidance citing logistics challenges and component shortages. The Industrial Select Sector SPDR fund declined 1.8% on the session. Supply chain experts suggest normalization could take another 6-12 months, particularly in sectors reliant on Asian suppliers.', 'Industrial stocks fall on supply chain guidance cuts', 'https://financial-news.example.com/article/1006', 'CAT,DE,HON,MMM', 'Industrials', 'FEATURE', '-0.2400', 'NEGATIVE', '0.6600', '2026-02-17 14:27:19.757'),
('NEWS0001007', '2025-12-09 16:07:19.757', 'Yahoo Finance', 'Michael Chen', 'Banking Sector Faces Regulatory Scrutiny', 'The banking sector faced increased scrutiny today as regulators announced plans for enhanced oversight of large financial institutions. New proposed rules would require banks to hold additional capital reserves and strengthen risk management practices. Bank stocks declined on average 2% as investors assessed the potential impact on profitability. Industry groups have signaled they will provide feedback during the public comment period.', 'Banks decline as regulators propose stricter capital rules', 'https://financial-news.example.com/article/1007', 'SPY,QQQ,DIA', 'Broad Market', 'MARKET_WRAP', '-0.2300', 'NEGATIVE', '0.6700', '2026-02-17 14:27:19.757'),
('NEWS0001008', '2025-12-09 14:27:19.757', 'Seeking Alpha', 'Emily Davis', 'Consumer Confidence Index Reaches New High', 'Consumer confidence surged to its highest level in two years according to the latest survey data released today. The index rose to 115.3 from 108.7 in the prior month, well above consensus estimates. Respondents cited improved job market conditions and moderating inflation as key factors boosting sentiment. The strong reading bodes well for consumer spending heading into the important holiday shopping season.', 'Consumer confidence hits 2-year high at 115.3', 'https://financial-news.example.com/article/1008', 'AAPL,MSFT,GOOGL,NVDA', 'Technology', 'BREAKING', '0.7800', 'POSITIVE', '0.6800', '2026-02-17 14:27:19.757'),
